import { Component, OnInit } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { MagicService } from '../../services/magic.service';
import { Magic } from '../../models/magic';
import { magi}

@Component({
  selector: 'app-magic-detail',
  templateUrl: './magic-detail.component.html',
  styleUrls: ['./magic-detail.component.css']
})
export class MagicDetailComponent implements OnInit {
  magicDetail!: MagicDetail;
  loading: boolean = true;
  error: string = '';

  constructor(
    private route: ActivatedRoute,
    private magicService: MagicService
  ) {}

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id')!;
    this.magicService.getMagiaDetalhe(id).subscribe({
      next: (data: Magic) => {
        this.magic = data;
        this.loading = false;
      },
      error: (err) => {
        this.error = 'Erro ao carregar os detalhes da magia.';
        this.loading = false;
      }
    });
  }

}
